-- SNA_Demo cluster + wallet seed (bear-market roster, 2026-06)
-- Run in Supabase after the cluster/variant migrations (see PAPER_TRADER_INSTRUCTIONS.md §4).

-- 1) wallet roster
CREATE TABLE IF NOT EXISTS sifter_dev.copy_wallets (
  address TEXT PRIMARY KEY, tier TEXT, role TEXT, runner_rate_pct NUMERIC,
  nonrunner_ev_pct NUMERIC, profit_factor NUMERIC, entry_style TEXT,
  signal_strength TEXT, selectable BOOLEAN);


-- 2) clusters
CREATE TABLE IF NOT EXISTS sifter_dev.copy_clusters (
  cluster_id TEXT PRIMARY KEY, is_bot_cluster BOOLEAN, members JSONB,
  shrunk_runner_rate_pct NUMERIC, nonrunner_ev_pct NUMERIC, signals_per_day NUMERIC,
  strength TEXT, co_entry_window_s INT DEFAULT 120, min_members_to_fire INT DEFAULT 2);

